from flask import Flask, request, jsonify
from pymongo import MongoClient, ASCENDING, DESCENDING
from bson import ObjectId
from datetime import datetime
import os

app = Flask(__name__)

MONGO_URI = os.getenv("MONGO_URI", "mongodb://localhost:27017")
DB_NAME = os.getenv("MONGO_DB", "cms_db")

client = MongoClient(MONGO_URI)
db = client[DB_NAME]

profiles = db["user_profiles"]
documents = db["documents"]

profiles.create_index([("user_id", ASCENDING)], unique=True)
documents.create_index([("author_id", ASCENDING)])
documents.create_index([("tags", ASCENDING)])
documents.create_index([("created_at", DESCENDING)])


def serialize_doc(doc):
    if not doc:
        return None
    doc["_id"] = str(doc["_id"])
    if "created_at" in doc and isinstance(doc["created_at"], datetime):
        doc["created_at"] = doc["created_at"].isoformat()
    if "updated_at" in doc and isinstance(doc["updated_at"], datetime):
        doc["updated_at"] = doc["updated_at"].isoformat()
    return doc


