@app.route("/documents/bulk", methods=["POST"])
def bulk_insert_documents():
    data = request.get_json(force=True) or {}
    items = data.get("documents", [])
    if not isinstance(items, list) or not items:
        return jsonify({"error": "documents must be a non-empty list"}), 400

    now = datetime.utcnow()
    prepared = []
    for item in items:
        title = item.get("title")
        content = item.get("content")
        author_id = item.get("author_id")
        if not title or not content or not author_id:
            return jsonify({"error": "each document requires title, content, and author_id"}), 400
        prepared.append({
            "title": title,
            "content": content,
            "author_id": author_id,
            "tags": item.get("tags", []),
            "status": item.get("status", "draft"),
            "metadata": item.get("metadata", {}),
            "created_at": now,
            "updated_at": now,
        })

    result = documents.insert_many(prepared)
    return jsonify({"inserted_ids": [str(i) for i in result.inserted_ids]}), 201


